const githubResponse = $input.first().json;
const input = $('Ejecutar por Workflow').first().json;

const timestamp = input.timestamp || new Date().toISOString();
const date = timestamp.split('T')[0];
const time = (timestamp.split('T')[1] || '00:00').substring(0, 5);
const evento = input.evento || 'EVENTO';
const pieza = input.pieza || '—';
const detalles = input.detalles || '';

const logLine = `| ${date} | ${time} | ${evento} | ${pieza} | ${detalles} |`;

let existingContent = '';
let sha = null;

if (githubResponse.content) {
  // File exists — decode and get SHA
  existingContent = Buffer.from(githubResponse.content, 'base64').toString('utf8');
  sha = githubResponse.sha;
} else {
  // New file
  existingContent = '# FG Operations Log\n\n| Fecha | Hora | Evento | Pieza | Detalles |\n|-------|------|--------|-------|----------|\n';
}

const newContent = existingContent + logLine + '\n';
const base64Content = Buffer.from(newContent).toString('base64');

return [{ json: { base64Content, sha, logLine, logged: true } }];
